[{'połączenia': " . $mysqli->connect_error);\n}\n\n// Lista instancji demo z przypisanymi modułami\n$tenants = [\n    'agencja' => 'zillapage", 'beauty\' => \'appointly\',\n    \'ecommerce\' => \'products\',\n    \'eventy\' => \'flexstage\',\n    \'gastronomia\' => \'catering_management_module\',\n    \'hotel\' => \'hotel_management_system\',\n    \'kursy\' => \'flexacademy\',\n    \'logistyka\' => \'logistic\',\n    \'medycyna\' => \'appointly\',\n    \'nieruchomosci\' => \'realestate\',\n    \'oze\' => \'projects\',\n    \'rekrutacja\' => \'recruitment\',\n    \'serwiswww\' => \'website_maintenance_management\',\n    \'warsztat\' => \'workshop\',\n];\n\necho "Aktywacja modułów branżowych...\n";\n\nforeach ($tenants as $slug => $module) {\n    $dbName = \'ps_\' . $slug;\n    $tableName = $slug . \'_tblmodules': 'Wybierz bazę danych\n    if (!$mysqli->select_db($dbName)) {\n        echo', 'dbName': 'continue;'}, {'Tabela $tableName nie istnieje w bazie $dbName': 'continue;'}, {'Moduł $module aktywowany dla instancji $slug': ''}, {'Błąd podczas aktywacji modułu $module dla instancji $slug: " . $mysqli->error . "': ''}]